submod u1(.rst_n(rst_n), .clk(clk), .rst_n_ext(rst1));
defparam u1.STAGES = 5;
defparam u1.NUM_OUT = 4;

genvar i;
for (i=0; i<STAGES+NUM_OUT-1; i=i+1)
begin
  always @(posedge clk or negedge rst_n)
  begin
    if (~rst_n) rst_reg[i] <= 1'b0;
    else if (i < STAGES) rst_reg[i] <= rst_reg[i-1];
    else rst_reg[i] <= rst_reg[STAGES-2];
  end
end

